const fs = require('fs');

const repo = (process.env.GITHUB_REPO || '').trim();
if (!repo) {
  return { check_error: 'GITHUB_REPO is not set in environment' };
}

const token = (process.env.GITHUB_TOKEN || '').trim();
const headers = {
  Accept: 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  'User-Agent': 'nanoclaw-pm-snippet',
};
if (token) headers.Authorization = `Bearer ${token}`;

const seenPath = '/workspace/group/seen_issues.json';
if (!fs.existsSync(seenPath)) {
  fs.writeFileSync(seenPath, JSON.stringify([], null, 2), 'utf8');
}

let rawSeen = [];
try {
  rawSeen = JSON.parse(fs.readFileSync(seenPath, 'utf8'));
} catch {
  rawSeen = [];
}

const seenNumbers = (Array.isArray(rawSeen) ? rawSeen : [])
  .map((value) => Number(value))
  .filter((value) => Number.isInteger(value));
const seenSet = new Set(seenNumbers);

let rawIssues;
try {
  const res = await fetch(`https://api.github.com/repos/${repo}/issues?state=open&per_page=100`, {
    headers,
  });
  if (!res.ok) {
    throw new Error(`HTTP ${res.status} ${res.statusText}`);
  }
  rawIssues = await res.json();
} catch (err) {
  return {
    repo,
    checked_at: context?.run_started_at,
    check_error: `issue fetch failed: ${err instanceof Error ? err.message : String(err)}`,
    new_issues: [],
    all_open_issue_numbers: [],
    seen_issue_numbers: Array.from(seenSet).sort((a, b) => a - b),
    seen_file_path: seenPath,
  };
}

const issues = [];
for (const issue of Array.isArray(rawIssues) ? rawIssues : []) {
  if (!issue || typeof issue !== 'object') continue;
  if (issue.pull_request) continue;
  const number = issue.number;
  if (!Number.isInteger(number)) continue;

  const labelsRaw = Array.isArray(issue.labels) ? issue.labels : [];
  const labels = [];
  for (const label of labelsRaw) {
    if (typeof label === 'string') labels.push(label);
    else if (label && typeof label === 'object' && typeof label.name === 'string') labels.push(label.name);
  }

  issues.push({
    number,
    title: typeof issue.title === 'string' ? issue.title : '',
    body: typeof issue.body === 'string' ? issue.body : '',
    labels,
    state: typeof issue.state === 'string' ? issue.state : 'open',
    url: typeof issue.html_url === 'string' ? issue.html_url : '',
  });
}

const allOpenNumbers = issues.map((issue) => issue.number).sort((a, b) => a - b);
const newIssues = issues.filter((issue) => !seenSet.has(issue.number));

if (newIssues.length === 0) {
  return false;
}

return {
  repo,
  checked_at: context?.run_started_at,
  new_issues: newIssues,
  all_open_issue_numbers: allOpenNumbers,
  seen_issue_numbers: Array.from(seenSet).sort((a, b) => a - b),
  seen_file_path: seenPath,
};
